package cmd

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// setupWorkFocusEnv initializes a test environment and populates its bead store.
func setupWorkFocusEnv(t *testing.T, beads ...*bead.Bead) *TestEnvironment {
	t.Helper()
	env := NewTestEnvironment(t)
	store := bead.NewStore(filepath.Join(env.Dir, ddxroot.DirName))
	require.NoError(t, store.Init(context.Background()))
	for _, b := range beads {
		require.NoError(t, store.Create(context.Background(), b))
	}
	return env
}

// TestWorkFocusReportsInterventionQueue verifies that proposed/operator-attention
// beads appear in human_required, and dependency-waiting beads appear
// in blocked_or_planning.
func TestWorkFocusReportsInterventionQueue(t *testing.T) {
	blocker := &bead.Bead{
		ID:    "ddx-focus-blocker",
		Title: "Blocker bead",
	}
	// Proposed bead (operator attention required).
	nhBead := &bead.Bead{
		ID:     "ddx-focus-nh",
		Title:  "Needs human attention",
		Status: bead.StatusProposed,
		Labels: []string{bead.LabelNeedsHuman},
		Extra: map[string]any{
			bead.ExtraNeedsHumanReason: "review returned terminal BLOCK",
		},
	}
	// Dependency-waiting bead (planning required before work can proceed).
	depBlocked := &bead.Bead{
		ID:    "ddx-focus-dep",
		Title: "Dep-blocked planning bead",
	}
	depBlocked.AddDep(blocker.ID, "blocks")

	env := setupWorkFocusEnv(t, blocker, nhBead, depBlocked)
	root := NewCommandFactory(env.Dir).NewRootCommand()

	out, err := executeCommand(root, "work", "focus", "--json")
	require.NoError(t, err)

	var report WorkFocusReport
	require.NoError(t, json.Unmarshal([]byte(out), &report))

	// Proposed bead must appear in human_required.
	var foundNH bool
	for _, item := range report.HumanRequired {
		if item.ID == nhBead.ID {
			foundNH = true
			assert.Equal(t, "review returned terminal BLOCK", item.Reason)
		}
	}
	assert.True(t, foundNH, "proposed bead must appear in human_required")

	// Proposed bead must NOT appear in blocked_or_planning.
	for _, item := range report.BlockedOrPlanning {
		assert.NotEqual(t, nhBead.ID, item.ID, "proposed bead must not appear in blocked_or_planning")
	}

	// Dependency-waiting bead must appear in blocked_or_planning.
	var foundDep bool
	for _, item := range report.BlockedOrPlanning {
		if item.ID == depBlocked.ID {
			foundDep = true
			assert.Equal(t, bead.BlockerKindDependency, item.BlockerKind)
		}
	}
	assert.True(t, foundDep, "dependency-waiting bead must appear in blocked_or_planning")
}

// TestWorkFocusOmitsWorkerReadyBeadsByDefault verifies that worker-ready
// (execution-eligible) beads are NOT listed as primary intervention items.
// They must appear only as a depth count in ready_summary.
func TestWorkFocusOmitsWorkerReadyBeadsByDefault(t *testing.T) {
	readyBead := &bead.Bead{
		ID:    "ddx-focus-ready",
		Title: "Ready for worker",
	}
	nhBead := &bead.Bead{
		ID:     "ddx-focus-nh2",
		Title:  "Needs human",
		Status: bead.StatusProposed,
		Labels: []string{bead.LabelNeedsHuman},
	}

	env := setupWorkFocusEnv(t, readyBead, nhBead)
	root := NewCommandFactory(env.Dir).NewRootCommand()

	out, err := executeCommand(root, "work", "focus", "--json")
	require.NoError(t, err)

	var report WorkFocusReport
	require.NoError(t, json.Unmarshal([]byte(out), &report))

	// Worker-ready bead must NOT appear in human_required.
	for _, item := range report.HumanRequired {
		assert.NotEqual(t, readyBead.ID, item.ID, "worker-ready bead must not be in human_required")
	}
	// Worker-ready bead must NOT appear in blocked_or_planning.
	for _, item := range report.BlockedOrPlanning {
		assert.NotEqual(t, readyBead.ID, item.ID, "worker-ready bead must not be in blocked_or_planning")
	}
	// The ready_summary must reflect the ready bead.
	assert.Equal(t, 1, report.ReadySummary.Count)
	assert.NotEmpty(t, report.ReadySummary.Depth)

	// The proposed bead must appear in human_required.
	var foundNH bool
	for _, item := range report.HumanRequired {
		if item.ID == nhBead.ID {
			foundNH = true
		}
	}
	assert.True(t, foundNH, "proposed bead must still appear in human_required")
}

// TestWorkFocusJSONIncludesUnknownHazards verifies that the JSON output's
// unknowns field surfaces capacity signals when in_progress beads are present.
func TestWorkFocusJSONIncludesUnknownHazards(t *testing.T) {
	// Create an in_progress bead by creating it as open then claiming it.
	b := &bead.Bead{
		ID:    "ddx-focus-ip",
		Title: "In-progress bead",
	}
	env := setupWorkFocusEnv(t, b)

	// Claim the bead to move it to in_progress.
	store := bead.NewStore(filepath.Join(env.Dir, ddxroot.DirName))
	require.NoError(t, store.Claim(b.ID, "test-worker"))

	root := NewCommandFactory(env.Dir).NewRootCommand()
	out, err := executeCommand(root, "work", "focus", "--json")
	require.NoError(t, err)

	var report WorkFocusReport
	require.NoError(t, json.Unmarshal([]byte(out), &report))

	// unknowns must be present and mention worker process liveness.
	require.NotEmpty(t, report.Unknowns, "unknowns must not be empty when in_progress beads exist")
	var foundLiveness bool
	for _, u := range report.Unknowns {
		if strings.Contains(u, "worker process liveness") || strings.Contains(u, "in_progress") {
			foundLiveness = true
		}
	}
	assert.True(t, foundLiveness, "unknowns must mention worker process liveness or in_progress count")
}

// TestWorkFocusRecommendsWorkerForDeepReadyQueue verifies the conservative
// worker-start suggestion when ready depth is high (>= 3) and no active
// workers are detected.
func TestWorkFocusRecommendsWorkerForDeepReadyQueue(t *testing.T) {
	var beads []*bead.Bead
	for i := 0; i < 4; i++ {
		beads = append(beads, &bead.Bead{
			ID:    "ddx-focus-deep-" + string(rune('a'+i)),
			Title: "Deep queue bead",
		})
	}

	env := setupWorkFocusEnv(t, beads...)
	root := NewCommandFactory(env.Dir).NewRootCommand()

	out, err := executeCommand(root, "work", "focus", "--json")
	require.NoError(t, err)

	var report WorkFocusReport
	require.NoError(t, json.Unmarshal([]byte(out), &report))

	assert.Equal(t, 4, report.ReadySummary.Count)
	assert.Equal(t, "deep", report.ReadySummary.Depth)
	// Worker recommendation must suggest running ddx work.
	assert.Contains(t, report.WorkerRecommendation, "ddx work",
		"worker recommendation must suggest 'ddx work' for deep ready queue")
}

// TestWorkFocusEmptyQueueExitsSuccessfully verifies AC1: ddx work focus is
// read-only and exits successfully on an empty queue.
func TestWorkFocusEmptyQueueExitsSuccessfully(t *testing.T) {
	env := setupWorkFocusEnv(t) // no beads
	root := NewCommandFactory(env.Dir).NewRootCommand()

	out, err := executeCommand(root, "work", "focus")
	require.NoError(t, err)
	assert.Contains(t, out, "Operator attention")
	assert.Contains(t, out, "Blocked / planning")
	assert.Contains(t, out, "Worker-ready summary")
	assert.Contains(t, out, "Worker recommendation")
	assert.Contains(t, out, "Unknowns")
}

// TestWorkFocusReportsActiveLongRunningWorkerFromWorkerStatus verifies AC #5:
// a fresh worker-status sidecar (last_activity_at within LivenessTTL) is
// reported as an active worker by `ddx work focus`, even when the bead
// tracker's claim timestamp has not moved. Without the sidecar, the same
// bead would appear merely as in_progress + an "unknown liveness" hazard.
func TestWorkFocusReportsActiveLongRunningWorkerFromWorkerStatus(t *testing.T) {
	b := &bead.Bead{
		ID:    "ddx-focus-active-worker",
		Title: "In-progress bead with live worker",
	}
	env := setupWorkFocusEnv(t, b)

	store := bead.NewStore(filepath.Join(env.Dir, ddxroot.DirName))
	require.NoError(t, store.Claim(b.ID, "test-worker"))

	// Write a fresh worker status sidecar so the focus report can detect
	// the live worker without consulting the (stale-by-design) tracker
	// claim timestamp.
	workerID := "wkr-focus-active"
	require.NoError(t, workerstatus.WriteLiveness(env.Dir, workerID, workerstatus.LivenessRecord{
		WorkerID:       workerID,
		ProjectRoot:    env.Dir,
		CurrentBead:    b.ID,
		AttemptID:      "att-focus-001",
		Phase:          "running",
		Harness:        "claude",
		Model:          "opus",
		PID:            os.Getpid(),
		LastActivityAt: time.Now().UTC(),
	}))

	root := NewCommandFactory(env.Dir).NewRootCommand()
	out, err := executeCommand(root, "work", "focus", "--json")
	require.NoError(t, err)

	var report WorkFocusReport
	require.NoError(t, json.Unmarshal([]byte(out), &report))

	require.Len(t, report.ActiveWorkers, 1,
		"focus must surface the live worker sidecar even when the tracker claim timestamp has not changed")
	assert.Equal(t, workerID, report.ActiveWorkers[0].WorkerID)
	assert.Equal(t, b.ID, report.ActiveWorkers[0].CurrentBead)
	assert.Equal(t, "att-focus-001", report.ActiveWorkers[0].AttemptID)
	assert.Equal(t, "running", report.ActiveWorkers[0].Phase)

	// The in_progress liveness "unknown" hazard must NOT be added when an
	// active sidecar is present — otherwise the focus report would
	// contradict itself.

package cmd

import (
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/activework"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/spf13/cobra"
)

// WorkFocusActiveWorker is one entry in the active_workers section.
type WorkFocusActiveWorker struct {
	WorkerID       string `json:"worker_id"`
	CurrentBead    string `json:"current_bead,omitempty"`
	AttemptID      string `json:"attempt_id,omitempty"`
	Phase          string `json:"phase,omitempty"`
	LastActivityAt string `json:"last_activity_at,omitempty"`
}

// WorkFocusBead is one item in the operator-attention section.
type WorkFocusBead struct {
	ID              string `json:"id"`
	Title           string `json:"title"`
	Reason          string `json:"reason,omitempty"`
	SuggestedAction string `json:"suggested_action,omitempty"`
}

// WorkFocusBlockedBead is one item in the blocked_or_planning section.
type WorkFocusBlockedBead struct {
	ID          string `json:"id"`
	Title       string `json:"title"`
	BlockerKind string `json:"blocker_kind"`
	Detail      string `json:"detail,omitempty"`
}

// WorkFocusReadySummary is the ready-queue depth summary.
type WorkFocusReadySummary struct {
	Count int    `json:"count"`
	Depth string `json:"depth"` // "empty", "shallow", "moderate", "deep"
}

// WorkFocusReport is the structured result of "ddx work focus".
type WorkFocusReport struct {
	HumanRequired        []WorkFocusBead         `json:"human_required"`
	BlockedOrPlanning    []WorkFocusBlockedBead  `json:"blocked_or_planning"`
	ReadySummary         WorkFocusReadySummary   `json:"ready_summary"`
	ActiveWorkers        []WorkFocusActiveWorker `json:"active_workers,omitempty"`
	ActiveWork           activework.Snapshot     `json:"active_work"`
	WorkerRecommendation string                  `json:"worker_recommendation"`
	Unknowns             []string                `json:"unknowns"`
}

// workerReadyDepthLabel returns a human-readable depth label for the ready count.
func workerReadyDepthLabel(count int) string {
	switch {
	case count == 0:
		return "empty"
	case count <= 1:
		return "shallow"
	case count <= 3:
		return "moderate"
	default:
		return "deep"
	}
}

// buildWorkFocusReport queries the store and returns a WorkFocusReport.
//
// projectRoot, when non-empty, enables the active_workers section and active
// work summary: fresh claim heartbeats, liveness sidecars, and run-state files
// are reconciled into one project-scoped view so the operator-facing answer
// stays aligned across bead, work, and GraphQL status surfaces.
func buildWorkFocusReport(store *bead.Store, projectRoot string) (WorkFocusReport, error) {
	// Collect operator-attention beads (status=proposed, any dep state).
	operatorAttentionBeads, err := store.ProposedOperatorAttention()
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: operator attention query: %w", err)
	}

	// Build a set of operator-attention IDs so we can exclude them from blocked section.
	operatorAttentionSet := make(map[string]bool, len(operatorAttentionBeads))
	humanRequired := make([]WorkFocusBead, 0, len(operatorAttentionBeads))
	for _, b := range operatorAttentionBeads {
		operatorAttentionSet[b.ID] = true
		meta := bead.GetNeedsHumanMeta(b)
		item := WorkFocusBead{
			ID:    b.ID,
			Title: b.Title,
		}
		if meta.Reason != "" {
			item.Reason = meta.Reason
		} else if meta.Summary != "" {
			item.Reason = meta.Summary
		}
		if meta.SuggestedAction != "" {
			item.SuggestedAction = meta.SuggestedAction
		}
		humanRequired = append(humanRequired, item)
	}

	// Collect all blocked beads; exclude operator-attention beads already captured above.
	allBlocked, err := store.BlockedAll()
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: blocked query: %w", err)
	}
	var blockedOrPlanning []WorkFocusBlockedBead
	for _, bb := range allBlocked {
		if operatorAttentionSet[bb.ID] {
			continue
		}
		item := WorkFocusBlockedBead{
			ID:          bb.ID,
			Title:       bb.Title,
			BlockerKind: bb.Blocker.Kind,
		}
		switch bb.Blocker.Kind {
		case bead.BlockerKindDependency:
			if len(bb.Blocker.UnclosedDepIDs) > 0 {
				item.Detail = "unclosed deps: " + strings.Join(bb.Blocker.UnclosedDepIDs, ", ")
			}
		case bead.BlockerKindRetryCooldown:
			if bb.Blocker.NextEligibleAt != "" {
				item.Detail = "retry after: " + bb.Blocker.NextEligibleAt
			}
		default:
			if bb.Blocker.Reason != "" {
				item.Detail = bb.Blocker.Reason
			}
		}
		blockedOrPlanning = append(blockedOrPlanning, item)
	}

	// Collect worker-ready depth.
	readyBeads, err := store.ReadyExecution()
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: ready query: %w", err)
	}
	readyCount := len(readyBeads)
	readySummary := WorkFocusReadySummary{
		Count: readyCount,
		Depth: workerReadyDepthLabel(readyCount),
	}

	// Observe in_progress beads as a capacity signal.
	inProgressBeads, err := store.List(bead.StatusInProgress, "", nil)
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: in_progress query: %w", err)
	}
	inProgressCount := len(inProgressBeads)

	// Shared active-work snapshot: claim heartbeats, worker liveness
	// sidecars, and run-state records are reconciled into one project-scoped
	// view so operator surfaces can agree on what is actually active.
	activeWork, err := collectActiveWorkSnapshot(projectRoot, store, time.Now())
	if err != nil {
		return WorkFocusReport{}, fmt.Errorf("work focus: active work query: %w", err)
	}
	activeWorkers := activeWorkRecordsForFocus(activeWork)

	// Conservative worker recommendation. Treat fresh active work as the
	// capacity signal rather than the raw lifecycle count.
	workerRec := buildWorkerRecommendation(readyCount, activeWork.Count)

	// Unknowns: worker process liveness is not verifiable from the bead store
	// alone; only add the hazard when we have in-progress beads but the only
	// active evidence is a claim heartbeat.
	var unknowns []string
	hasNonClaimActive := false
	for _, rec := range activeWork.Records {
		if rec.Source != "claim" {
			hasNonClaimActive = true
			break
		}
	}
	if inProgressCount > 0 && !hasNonClaimActive {
		unknowns = append(unknowns, fmt.Sprintf(
			"worker process liveness: %d bead(s) are in_progress but no active worker snapshot is fresh; check `ddx work status` for live processes",
			inProgressCount,
		))
	}

	return WorkFocusReport{
		HumanRequired:        humanRequired,
		BlockedOrPlanning:    blockedOrPlanning,
		ReadySummary:         readySummary,
		ActiveWorkers:        activeWorkers,
		ActiveWork:           activeWork,
		WorkerRecommendation: workerRec,
		Unknowns:             unknowns,
	}, nil
}

// buildWorkerRecommendation returns a conservative recommendation string.
// It suggests another worker only when ready depth is high and capacity is observable.
func buildWorkerRecommendation(readyCount, activeCount int) string {
	switch {
	case readyCount == 0:
		return "Queue is empty; no worker action needed."
	case activeCount > 0 && readyCount > 0:
		return fmt.Sprintf(
			"%d bead(s) ready; %d active worker(s) observed. Monitor progress or run 'ddx work' to add capacity.",
			readyCount, activeCount,
		)
	case readyCount >= 3:
		return fmt.Sprintf(
			"%d bead(s) ready and no active workers detected; consider running: ddx work",
			readyCount,
		)
	default:
		return fmt.Sprintf(
			"%d bead(s) ready; run 'ddx work' to process.",
			readyCount,
		)
	}
}

func (f *CommandFactory) newWorkFocusCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "focus",
		Short: "Show work requiring operator attention",
		Long: `focus shows a read-only summary of queue items that require operator
attention — proposed beads, external blockers, dependency-waiting or
planning-required beads — along with a conservative worker-capacity
recommendation based on observable queue depth and in-progress signals.

Unlike 'ddx work plan', focus is designed for interactive queue stewardship:
it surfaces the items workers will NOT pick up and recommends operator actions.
Worker-ready beads are not listed as primary intervention items; they appear
only as a depth summary.

	Use --json for machine-readable output with stable keys:
	  human_required, blocked_or_planning, ready_summary,
	  active_work, worker_recommendation, unknowns
	`,
		Example: `  # Show intervention queue in human-readable format
  ddx work focus

  # Machine-readable output
  ddx work focus --json | jq '.human_required'`,
		Args: cobra.NoArgs,
		RunE: f.runWorkFocus,
	}
	cmd.Flags().Bool("json", false, "Output as JSON object with stable keys")
	return cmd
}

func (f *CommandFactory) runWorkFocus(cmd *cobra.Command, _ []string) error {
	asJSON, _ := cmd.Flags().GetBool("json")

	ddxDir := resolveBeadStoreRoot(f.WorkingDir)
	store := bead.NewStore(ddxDir)

	report, err := buildWorkFocusReport(store, f.WorkingDir)
	if err != nil {
		return err
	}

		if errors.As(checkErr, &resourceErr) {
			resourceResult := resourceErr.Result
			if resourceResult.ProjectRoot == "" && len(resourceResult.RootChecks) == 0 {
				resourceResult = checkResult
			}
			report := ExecuteBeadReport{
				WorkerID:          runtime.WorkerID,
				Harness:           harness,
				Model:             model,
				Status:            ExecuteBeadStatusResourceExhausted,
				Detail:            ResourceExhaustedStopMessage,
				Error:             resourceErr.Error(),
				SessionID:         runtime.SessionID,
				ResourceExhausted: &resourceResult,
				Disrupted:         true,
				DisruptionReason:  ReadinessSystemReasonResourceExhausted,
				OutcomeReason:     ReadinessSystemReasonResourceExhausted,
			}
			result.Failures++
			result.LastFailureStatus = report.Status
			result.Results = append(result.Results, report)
			setExit("ResourceExhausted", "resource_exhausted")
			emitResourceExhausted(emit, nil, "", report, assignee, now().UTC())
			if runtime.Log != nil {
				_, _ = fmt.Fprintln(runtime.Log, ResourceExhaustedStopMessage)
			}
			return executeBeadIterationOutcome{Stop: true}, nil
		}
		setExit("Preflight", "preflight_failed")
		return executeBeadIterationOutcome{Stop: true}, checkErr
	}
}
if runtime.BinaryRefreshCheck != nil {
	refreshed, refreshErr := runtime.BinaryRefreshCheck(ctx)
	if refreshErr != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "binary refresh check failed: %v; continuing\n", refreshErr)
		}
		emit("loop.binary_refresh_check_error", map[string]any{"error": refreshErr.Error()})
	} else if refreshed {
		setExit("BinaryRefresh", "binary_refresh")
		emit("loop.binary_refresh", map[string]any{"reason": "installed_binary_changed"})
		return executeBeadIterationOutcome{Stop: true}, nil
	}
}
if runtime.ProjectRootDirtyCheck != nil && runtime.ProjectRoot != "" {
	if dirtyPaths := runtime.ProjectRootDirtyCheck(runtime.ProjectRoot); len(dirtyPaths) > 0 {
		guardState, escalated, guardErr := updateDirtyRootGuardState(
			runtime.ProjectRoot,
			dirtyPaths,
			now().UTC(),
			DefaultDirtyRootEscalationThreshold,
			DirtyRootEscalationCooldown,
		)
		if guardErr != nil && runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "dirty-root guard persistence failed: %v\n", guardErr)
		}
		reason := "dirty_project_root"
		retryAfter := ""
		message := fmt.Sprintf(
			"project root has uncommitted tracked changes (%s); resolve before resuming autonomous work",
			strings.Join(normalizeDirtyRootPaths(dirtyPaths), ", "),
		)
		if guardState != nil {
			if len(guardState.DirtyPaths) > 0 {
				dirtyPaths = append([]string(nil), guardState.DirtyPaths...)
			}
			if escalated {
				reason = "dirty_project_root_repeated"
				retryAfter = guardState.RetryAfter.UTC().Format(time.RFC3339)
				message = fmt.Sprintf(
					"project root has uncommitted tracked changes (%s); relaunch suppressed until %s",
					strings.Join(dirtyPaths, ", "),
					retryAfter,
				)
			}
		}
		result.OperatorAttention = &OperatorAttentionStop{
			Reason:      reason,
			ProjectRoot: runtime.ProjectRoot,
			DirtyPaths:  dirtyPaths,
			RetryAfter:  retryAfter,
			Message:     message,
		}
		setExit("OperatorAttention", "operator_attention")
		emit("loop.operator_attention", map[string]any{
			"reason":       reason,
			"project_root": runtime.ProjectRoot,
			"dirty_paths":  dirtyPaths,
			"retry_after":  retryAfter,
			"message":      message,
		})
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", message)
		}
		return executeBeadIterationOutcome{Stop: true}, nil
	}
	if guardErr := clearDirtyRootGuardState(runtime.ProjectRoot); guardErr != nil && runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "dirty-root guard clear failed: %v\n", guardErr)
	}
}

	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(report)
	}
	return printWorkFocusText(cmd, report)
}

func printWorkFocusText(cmd *cobra.Command, r WorkFocusReport) error {
	out := cmd.OutOrStdout()

	// Section: Operator attention
	fmt.Fprintf(out, "=== Operator attention (%d) ===\n", len(r.HumanRequired))
	if len(r.HumanRequired) == 0 {
		fmt.Fprintln(out, "  (none)")
	} else {
		for _, item := range r.HumanRequired {
			fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
			if item.Reason != "" {
				fmt.Fprintf(out, "       reason: %s\n", item.Reason)
			}
			if item.SuggestedAction != "" {
				fmt.Fprintf(out, "       suggested action: %s\n", item.SuggestedAction)
			}
		}
	}

	// Section: Blocked / planning
	fmt.Fprintf(out, "\n=== Blocked / planning (%d) ===\n", len(r.BlockedOrPlanning))
	if len(r.BlockedOrPlanning) == 0 {
		fmt.Fprintln(out, "  (none)")
	} else {
		for _, item := range r.BlockedOrPlanning {
			fmt.Fprintf(out, "  [%s] %s\n", item.ID, item.Title)
			if item.Detail != "" {
				fmt.Fprintf(out, "       blocker: %s — %s\n", item.BlockerKind, item.Detail)
			} else {
				fmt.Fprintf(out, "       blocker: %s\n", item.BlockerKind)
			}
		}
	}

	// Section: Worker-ready summary
	fmt.Fprintf(out, "\n=== Worker-ready summary ===\n")
	fmt.Fprintf(out, "  %d bead(s) ready for worker execution (%s)\n", r.ReadySummary.Count, r.ReadySummary.Depth)

	// Section: Active workers (sidecar-derived). Surfaced so an operator
	// asking "is the worker alive?" gets a positive answer even when the
	// bead tracker's claim timestamp has not advanced.
	if len(r.ActiveWorkers) > 0 {
		fmt.Fprintf(out, "\n=== Active workers (%d) ===\n", len(r.ActiveWorkers))
		for _, w := range r.ActiveWorkers {
			fmt.Fprintf(out, "  [%s] bead=%s attempt=%s phase=%s last=%s\n",
				w.WorkerID, dashIfEmpty(w.CurrentBead), dashIfEmpty(w.AttemptID),
				dashIfEmpty(w.Phase), w.LastActivityAt)
		}
	}

	// Section: Worker recommendation
	fmt.Fprintf(out, "\n=== Worker recommendation ===\n")
	fmt.Fprintf(out, "  %s\n", r.WorkerRecommendation)

	// Section: Unknowns
	fmt.Fprintf(out, "\n=== Unknowns ===\n")
	if len(r.Unknowns) == 0 {
		fmt.Fprintln(out, "  (none)")
	} else {
		for _, u := range r.Unknowns {
			fmt.Fprintf(out, "  - %s\n", u)
		}
	}

	return nil
}

func dashIfEmpty(s string) string {
	if s == "" {
		return "-"
	}
	return s
}

	// contradict itself.
	for _, u := range report.Unknowns {
		assert.NotContains(t, u, "worker process liveness",
